{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/PropertyWrappingRuleIndentationBestEffortTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

internal class PropertyWrappingRuleIndentationBestEffortTest {
    private val propertyWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { PropertyWrappingRule() }

    @Test
    fun `Given that indent size is unset then indent wrapped property value with a best effort continuation indent`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                            $EOL_CHAR
            class Foo {
                private val deferredMessageQueueSubscription = DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            }
            """.trimIndent()

        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                            $EOL_CHAR
            class Foo {
                private val deferredMessageQueueSubscription =
                    DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            }
            """.trimIndent()

        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to "unset")
            .isFormattedAs(formattedCode)
    }
}
"}

